'use strict';

// MODULES //

import isRowMajorString from '@stdlib/ndarray-base-assert-is-row-major-string';
import normalizeIndex from '@stdlib/ndarray-base-normalize-index';
import strides2order from '@stdlib/ndarray-base-strides2order';
import getDType from '@stdlib/ndarray-base-dtype';
import getShape from '@stdlib/ndarray-base-shape';
import getStrides from '@stdlib/ndarray-base-strides';
import getOffset from '@stdlib/ndarray-base-offset';
import getOrder from '@stdlib/ndarray-base-order';
import getData from '@stdlib/ndarray-base-data-buffer';
import format from '@stdlib/error-tools-fmtprodmsg';


// MAIN //

/**
* Expands the shape of an array by inserting a new dimension of size one at a specified dimension index.
*
* ## Notes
*
* -   A provided dimension index must reside on the interval `[-N-1, N]`, where `N` is the rank (i.e., number of dimensions) of the provided input array. If provided a negative dimension index, the position at which to insert a singleton dimension is computed as `N + dim + 1`. Hence, if provided `-1`, the resolved position is `N` (i.e., a singleton dimension is appended to the input array).
*
* @param {ndarray} x - input array
* @param {integer} dim - dimension index at which to insert a singleton dimension
* @param {boolean} writable - boolean indicating whether the returned ndarray should be writable
* @throws {RangeError} must provide a valid dimension index
* @returns {ndarray} output array
*
* @example
* import array from '@stdlib/ndarray-array';
*
* var x = array( [ [ 1, 2 ], [ 3, 4 ] ] );
* // returns <ndarray>[ [ 1, 2 ], [ 3, 4 ] ]
*
* var y = expandDimensions( x, 1, false );
* // returns <ndarray>[ [ [ 1, 2 ] ], [ [ 3, 4 ] ] ]
*/
function expandDimensions( x, dim, writable ) {
	var strides;
	var shape;
	var isrm;
	var ord;
	var sh;
	var st;
	var d;
	var o;
	var N;
	var i;

	sh = getShape( x, false );
	st = getStrides( x, false );
	ord = getOrder( x );

	o = strides2order( st );
	if ( o === 0 || o === 3 ) {
		// Fallback to stated layout when unable to infer the underlying physical layout:
		isrm = isRowMajorString( ord );
	} else {
		isrm = ( o === 1 );
	}
	N = sh.length;

	strides = [];
	shape = [];

	d = normalizeIndex( dim, N );
	if ( d === -1 ) {
		throw new RangeError( format( 'invalid argument. Specified dimension index is out-of-bounds. Must be on the interval: [-%u, %u]. Value: `%d`.', N+1, N, dim ) );
	}
	if ( d === 0 ) {
		// Prepend singleton dimension...
		shape.push( 1 );
		if ( isrm ) {
			strides.push( sh[ 0 ] * st[ 0 ] );
		} else {
			strides.push( st[ 0 ] );
		}
		// Copy remaining dimensions...
		for ( i = 0; i < N; i++ ) {
			shape.push( sh[ i ] );
			strides.push( st[ i ] );
		}
	} else if ( d === N ) {
		// Copy dimensions...
		for ( i = 0; i < N; i++ ) {
			shape.push( sh[ i ] );
			strides.push( st[ i ] );
		}
		// Append singleton dimension...
		shape.push( 1 );
		if ( isrm ) {
			strides.push( st[ N-1 ] );
		} else {
			strides.push( sh[ N-1 ] * st[ N-1 ] );
		}
	} else {
		// Insert a singleton dimension...
		for ( i = 0; i < N+1; i++ ) {
			if ( i === d ) {
				shape.push( 1 );
				if ( isrm ) {
					strides.push( st[ i-1 ] );
				} else { // ord === 'column-major'
					strides.push( st[ i ] );
				}
			} else if ( i < d ) {
				shape.push( sh[ i ] );
				strides.push( st[ i ] );
			} else { // i > d
				shape.push( sh[ i-1 ] );
				strides.push( st[ i-1 ] );
			}
		}
	}
	return new x.constructor( getDType( x ), getData( x ), shape, strides, getOffset( x ), ord, { // eslint-disable-line max-len
		'readonly': !writable
	});
}


// EXPORTS //

export default expandDimensions;
